export const cacheService = { store: new Map<string, { value: any; expiresAt: number }>(), async get<T>(key: string): Promise<T | null> { const item = this.store.get(key); if (!item || item.expiresAt < Date.now()) { this.store.delete(key); return null; } return item.value as T; }, async set(key: string, value: any, ttlSeconds: number = 300) { this.store.set(key, { value, expiresAt: Date.now() + ttlSeconds * 1000 }); }, async delete(key: string) { this.store.delete(key); }, async flush() { this.store.clear(); }, async getOrSet<T>(key: string, factory: () => Promise<T>, ttl: number = 300): Promise<T> { const cached = await this.get<T>(key); if (cached) return cached; const value = await factory(); await this.set(key, value, ttl); return value; } };
